#include <vector>
using namespace std;

bool solve(vector<long long> nums) {
    int n = nums.size();
    for (int p = 1; p <= n - 3; ++p) {
        bool first_ok = true;
        for (int i = 0; i < p; ++i) {
            if (nums[i] >= nums[i + 1]) {
                first_ok = false;
                break;
            }
        }
        if (!first_ok) continue;
        for (int q = p + 1; q <= n - 2; ++q) {
            bool middle_ok = true;
            for (int i = p; i < q; ++i) {
                if (nums[i] <= nums[i + 1]) {
                    middle_ok = false;
                    break;
                }
            }
            if (!middle_ok) continue;
            bool last_ok = true;
            for (int i = q; i < n - 1; ++i) {
                if (nums[i] >= nums[i + 1]) {
                    last_ok = false;
                    break;
                }
            }
            if (last_ok) return true;
        }
    }
    return false;
}
